bool is_async = RPC_IS_ASYNC(task);\n\n\trpc_set_active(task);\n\trpc_make_runnable(task);\n\tif (!is_async)\n\t\t__rpc_execute(task);", "numLines": 60, "startLine": 760, "totalLines": 1142}}

